sql:
SELECT MAX(total_score) AS highest_total_score
FROM academic_performance
WHERE year = 2021 AND grade = 'A+';

external_knowledge:
- 'learners' refers to students;
- 'submitted their tasks' means the assignments have a non-null submission date;
- 'instructors' refers to teachers.

- "students who haven't handed in any of their overdue assignments" refers to students without entries in the `assignment_submissions` table for assignments with due dates in the past;
- "overall scores" corresponds to `total_score` which is a combination of all assessments;
- "deadlines they missed" refers to `due_date` where the due date is earlier than the current date.

sql:
SELECT student_id, total_score
FROM academic_performance
WHERE total_score > 85;

SELECT assignment_id, student_id
FROM assignment_submissions
WHERE submission_id = 1;

SELECT MAX(student_count) AS max_student_count
FROM (
  SELECT class_id, COUNT(student_id) AS student_count
  FROM students
  GROUP BY class_id
);

SELECT class_id, MAX(total_score) AS highest_total_score
FROM academic_performance
GROUP BY class_id;

SELECT class_id, class_name
FROM classes
WHERE class_id > 0;
